    describe('getTimezone', function() {
        it('should return a timezone object for valid timezone name', function() {
            const timezone = countries_and_timezones.getTimezone('America/New_York');

            assert.strictEqual(typeof timezone, 'object');
            assert.strictEqual(timezone.name, 'America/New_York');
            assert.strictEqual(typeof timezone.utcOffset, 'number');
            assert.strictEqual(typeof timezone.utcOffsetStr, 'string');
            assert.strictEqual(typeof timezone.dstOffset, 'number');
            assert.strictEqual(typeof timezone.dstOffsetStr, 'string');
            assert.strictEqual(Array.isArray(timezone.countries), true);
        });

        it('should return null for invalid timezone name', function() {
            const timezone = countries_and_timezones.getTimezone('Invalid/Timezone');

            assert.strictEqual(timezone, null);
        });

        it('should return a new object instance each time (not cached reference)', function() {
            const timezone1 = countries_and_timezones.getTimezone('Europe/London');
            const timezone2 = countries_and_timezones.getTimezone('Europe/London');

            assert.notStrictEqual(timezone1, timezone2);
            assert.deepStrictEqual(timezone1, timezone2);
        });

        it('should handle UTC timezone correctly', function() {
            const timezone = countries_and_timezones.getTimezone('UTC');

            assert.strictEqual(typeof timezone, 'object');
            assert.strictEqual(timezone.name, 'UTC');
            assert.strictEqual(timezone.utcOffset, 0);
            assert.strictEqual(timezone.dstOffset, 0);
        });

        it('should return null for empty string', function() {
            const timezone = countries_and_timezones.getTimezone('');

            assert.strictEqual(timezone, null);
        });

        it('should return null for undefined input', function() {
            const timezone = countries_and_timezones.getTimezone(undefined);

            assert.strictEqual(timezone, null);
        });

        it('should return timezone with correct properties for Asia/Tokyo', function() {
            const timezone = countries_and_timezones.getTimezone('Asia/Tokyo');

            assert.strictEqual(typeof timezone, 'object');
            assert.strictEqual(timezone.name, 'Asia/Tokyo');
            assert.strictEqual(timezone.utcOffset, 540); // +9 hours in minutes
            assert.strictEqual(timezone.utcOffsetStr, '+09:00');
            assert.strictEqual(timezone.dstOffset, 0);
            assert.strictEqual(timezone.dstOffsetStr, '+00:00');
            assert.strictEqual(Array.isArray(timezone.countries), true);
            assert.strictEqual(timezone.countries.includes('JP'), true);
        });
    });
});
